1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSE_RATE = 0.5;
4	const HIGH_ENCH_THRESHOLD = 5;
5	const HIGH_ENCH_RATE = 0.3;
6	const BLOCK_SIZE = 3;
7	const BLOCK_PREMIUM = 60;
8	const LOYALTY_THRESHOLD = 2;
9	const LOYALTY_RATE = 0.2;
10	
11	const BASE_PREMIUMS: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	  rune: 25,
17	  moonstone: 25,
18	};
19	
20	type Item = { type: string; cursed?: boolean; enchantment?: number };
21	
22	const COMPONENT_TYPES = ["rune", "moonstone"];
23	
24	const isComponent = (item: Item): boolean => COMPONENT_TYPES.includes(item.type);
25	
26	const sum = (values: number[]): number =>
27	  values.reduce((total, value) => total + value, 0);
28	
29	const sumOfBasePremiums = (items: Item[]): number =>
30	  sum(items.map((item) => BASE_PREMIUMS[item.type]));
31	
32	const groupByType = (items: Item[]): Item[][] => {
33	  const groups: Record<string, Item[]> = {};
34	  for (const item of items) {
35	    if (!groups[item.type]) groups[item.type] = [];
36	    groups[item.type].push(item);
37	  }
38	  return Object.values(groups);
39	};
40	
41	const basePremiumForComponentGroup = (group: Item[]): number =>
42	  group.length === BLOCK_SIZE ? BLOCK_PREMIUM : sumOfBasePremiums(group);
43	
44	const basePremiumFor = (items: Item[]): number => {
45	  const components = items.filter(isComponent);
46	  const nonComponents = items.filter((item) => !isComponent(item));
47	  const componentGroupPremiums = groupByType(components).map(basePremiumForComponentGroup);
48	  return sum(componentGroupPremiums) + sumOfBasePremiums(nonComponents);
49	};
50	
51	const surchargeFor = (
52	  items: Item[],
53	  rate: number,
54	  applies: (item: Item) => boolean,
55	): number =>
56	  sum(items.map((item) => (applies(item) ? BASE_PREMIUMS[item.type] * rate : 0)));
57	
58	const isCursed = (item: Item): boolean => item.cursed === true;
59	const isHighlyEnchanted = (item: Item): boolean =>
60	  (item.enchantment ?? 0) >= HIGH_ENCH_THRESHOLD;
61	
62	const quotePremium = (items: Item[], yearsWithMHPCO: number): number => {
63	  const base = basePremiumFor(items);
64	  const curseSurcharge = surchargeFor(items, CURSE_RATE, isCursed);
65	  const highEnchSurcharge = surchargeFor(items, HIGH_ENCH_RATE, isHighlyEnchanted);
66	  const loyaltyDiscount = yearsWithMHPCO >= LOYALTY_THRESHOLD ? base * LOYALTY_RATE : 0;
67	  return Math.ceil(base + curseSurcharge + highEnchSurcharge - loyaltyDiscount + base * FIRST_INSURANCE_RATE + PROCESSING_FEE);
68	};
69	
70	export const runScenario = (scenario: any): unknown => {
71	  const items = scenario.steps[0].items;
72	  const yearsWithMHPCO = scenario.customer?.yearsWithMHPCO ?? 0;
73	  return { results: [{ premium: quotePremium(items, yearsWithMHPCO) }] };
74	};
